// Check if a YouTube video ID is available to write back.
// If the upload was skipped or failed, skip the video.json update.
const ctx = $input.first().json;

if (!ctx.youtube_video_id) {
  return [{
    json: {
      ...ctx,
      video_reference_updated: false,
      video_reference_skip_reason: 'No youtube_video_id available (upload was skipped or failed)'
    }
  }];
}

return [{ json: { ...ctx, video_reference_updated: null } }];

// Parse the existing video.json, inject youtube_video_id and video_id,
// and prepare the updated content for GitHub PUT.
const ctx = $('Check Video ID Available').first().json;
const ghResponse = $input.first().json;

// Derive HTTP status — mirrors the pattern from 09_publish_to_github.json.
// n8n's httpRequest with ignoreResponseCode=true exposes the HTTP status code
// via the _statusCode field, statusCode, or the message body.
const statusCode = Number(
  ghResponse?._statusCode
  ?? ghResponse?.statusCode
  ?? (String(ghResponse?.message || '').match(/\b(\d{3})\b/) || [])[1]
  ?? 0
);

if (statusCode === 404) {
  throw new Error(`video.json not found at content/topics/${ctx.topic_slug}/${ctx.date_key}/video.json — cannot update video reference without existing file`);
}

if (statusCode && statusCode !== 200) {
  const details = ghResponse?.message || ghResponse?.error || ghResponse?.errors?.[0]?.message || 'Unknown GitHub API error';
  throw new Error(`Failed to fetch existing video.json from GitHub (status ${statusCode}) for content/topics/${ctx.topic_slug}/${ctx.date_key}/video.json: ${details}`);
}

const existingSha = ghResponse?.sha || null;
if (!existingSha) {
  throw new Error(`GitHub returned an unexpected response for content/topics/${ctx.topic_slug}/${ctx.date_key}/video.json: missing sha in successful response`);
}

// Decode existing content from base64
let videoData;
try {
  const rawContent = Buffer.from(ghResponse.content, 'base64').toString('utf8');
  videoData = JSON.parse(rawContent);
} catch (e) {
  throw new Error(`Failed to parse existing video.json: ${e.message}`);
}

// Update the video reference fields
videoData.video_id = ctx.youtube_video_id;
videoData.youtube_video_id = ctx.youtube_video_id;

const updatedContent = JSON.stringify(videoData, null, 2);

return [{
  json: {
    ...ctx,
    _video_json_content: updatedContent,
    _video_json_sha: existingSha,
    _video_json_path: `content/topics/${ctx.topic_slug}/${ctx.date_key}/video.json`
  }
}];

