// Confirm GitHub write and extract commit SHA.
const ctx = $('Build Updated video.json').first().json;
const writeResp = $input.first().json;

const commitSha = writeResp?.commit?.sha || null;

return [{
  json: {
    topic_slug: ctx.topic_slug,
    date_key: ctx.date_key,
    youtube_video_id: ctx.youtube_video_id,
    video_reference_updated: true,
    video_reference_commit_sha: commitSha
  }
}];

